import React from 'react';
import { Box, Card, Divider, Heading, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionIcon = (conditionText: string): string => {
  const normalized = conditionText.toLowerCase();

  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  if (
    normalized.includes('rain') ||
    normalized.includes('drizzle') ||
    normalized.includes('shower')
  ) {
    return '🌧️';
  }
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('partly cloudy')) return '⛅';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';

  return '🌤️';
};

export default function GeneratedComponent({
  city = 'Tokyo',
  temperature = 28,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 8,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 30, low: 22 },
    { day: 'Tue', icon: '⛅', high: 27, low: 20 },
    { day: 'Wed', icon: '🌧️', high: 24, low: 19 },
    { day: 'Thu', icon: '☁️', high: 25, low: 18 },
    { day: 'Fri', icon: '🌤️', high: 29, low: 21 },
  ],
}: Props) {
  const resolvedUnit = unit || 'C';
  const currentIcon = getConditionIcon(condition);

  return (
    <Card
      shadow="md"
      radius="xl"
      border={true}
      padding={24}
      role="region"
      aria-label={`${city} weather`}
    >
      <Stack direction="vertical" gap={16}>
        <Stack direction="horizontal" justify="between" align="start" wrap={true} gap={12}>
          <Stack gap={4}>
            <Text
              variant="overline"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Weather
            </Text>
            <Heading
              level={4}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {city}
            </Heading>
            <Text
              variant="bodyLarge"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          <Stack gap={4} align="end">
            <Text
              as="div"
              size="4xl"
              color="var(--ggui-color-primary-600, #0284c7)"
              align="right"
            >
              <span aria-hidden="true">{currentIcon}</span>
            </Text>
            <Text
              variant="body"
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              align="right"
            >
              {temperature}°{resolvedUnit}
            </Text>
          </Stack>
        </Stack>

        <Box
          paddingX={16}
          paddingY={12}
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" justify="between" align="center" wrap={true} gap={12}>
            <Stack gap={2}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="label"
                size="lg"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidity}%
              </Text>
            </Stack>

            <Stack gap={2} align="end">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text
                variant="label"
                size="lg"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider orientation="horizontal" margin={4} color="var(--ggui-color-outline, #d4d4d8)" />

        <Stack direction="vertical" gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            5-day forecast
          </Text>

          <Stack
            direction="horizontal"
            gap={8}
            justify="between"
            align="stretch"
            wrap={false}
            role="group"
            aria-label="5-day forecast"
          >
            {forecast.map((item, index) => {
              const dayLabel = item.day || '--';
              const icon = item.icon || getConditionIcon(condition);
              const highDisplay = item.high !== undefined ? `H: ${item.high}°` : 'H: --°';
              const lowDisplay = item.low !== undefined ? `L: ${item.low}°` : 'L: --°';

              return (
                <Box
                  key={`${item.day || 'day'}-${index}`}
                  paddingY={12}
                  paddingX={8}
                  background="var(--ggui-color-surface, #fafafa)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  margin={0}
                >
                  <Stack gap={6} align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {dayLabel}
                    </Text>
                    <Text
                      as="div"
                      size="2xl"
                      color="var(--ggui-color-primary-600, #0284c7)"
                    >
                      <span aria-hidden="true">{icon}</span>
                    </Text>
                    <Stack direction="vertical" gap={2} align="center">
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {highDisplay}
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {lowDisplay}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

